```java
// MiniGitRepo.java
import java.io.*;
import java.nio.file.*;
import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.util.*;

public class MiniGitRepo {
    private final String repoDir;
    private final String objectsDir;
    private final String commitsDir;
    private final String indexFile;
    private final String headFile;

    public MiniGitRepo(String root) {
        this.repoDir = "." + File.separator + ".minigit";
        this.objectsDir = repoDir + File.separator + "objects";
        this.commitsDir = repoDir + File.separator + "commits";
        this.indexFile = repoDir + File.separator + "index";
        this.headFile = repoDir + File.separator + "HEAD";
    }

    public void init() {
        try {
            if (Files.exists(Paths.get(repoDir))) {
                System.out.println("minigit repo already exists");
                return;
            }
            Files.createDirectory(Paths.get(repoDir));
            Files.createDirectory(Paths.get(objectsDir));
            Files.createDirectory(Paths.get(commitsDir));
            Files.createFile(Paths.get(indexFile));
            Files.write(Paths.get(headFile), Arrays.asList(""), StandardCharsets.UTF_8);
            System.out.println("Initialized empty minigit repository in .minigit");
        } catch (IOException e) {
            System.err.println("init error: " + e);
        }
    }

    public void add(String filename) {
        try {
            File file = new File(filename);
            if (!file.exists()) {
                System.out.println("minigit add: file does not exist");
                return;
            }
            List<String> tracked = Files.readAllLines(Paths.get(indexFile));
            if (!tracked.contains(filename)) {
                tracked.add(filename);
                Files.write(Paths.get(indexFile), tracked, StandardCharsets.UTF_8);
                System.out.println("added " + filename);
            } else {
                System.out.println(filename + " already added");
            }
        } catch (IOException e) {
            System.err.println("add error: " + e);
        }
    }

    public void commit(String message) {
        try {
            List<String> tracked = Files.readAllLines(Paths.get(indexFile));
            if (tracked.isEmpty()) {
                System.out.println("nothing to commit");
                return;
            }
            Map<String, String> fileToSHA = new HashMap<>();
            for (String filename : tracked) {
                if (!Files.exists(Paths.get(filename))) {
                    System.out.println("commit error: file " + filename + " missing");
                    return;
                }
                // Hash file content
                byte[] content = Files.readAllBytes(Paths.get(filename));
                String sha = toSHA1(content);
                fileToSHA.put(filename, sha);
                // Save object
                String objPath = objectsDir + File.separator + sha;
                if (!Files.exists(Paths.get(objPath)))
                    Files.write(Paths.get(objPath), content);
            }

            // Commit id: random?
            String commitContent = "";
            for (Map.Entry<String, String> ent : fileToSHA.entrySet()) {
                commitContent += ent.getKey() + " " + ent.getValue() + "\n";
            }
            commitContent += "\n" + message + "\n";

            String commitId = toSHA1(commitContent.getBytes(StandardCharsets.UTF_8)).substring(0, 6);

            Files.write(Paths.get(commitsDir + File.separator + commitId),
                        Arrays.asList(commitContent), StandardCharsets.UTF_8);
            Files.write(Paths.get(headFile), Arrays.asList(commitId), StandardCharsets.UTF_8);

            System.out.println("Committed as " + commitId);
        } catch (IOException e) {
            System.err.println("commit error: " + e);
        }
    }

    public void status() {
        try {
            List<String> tracked = Files.readAllLines(Paths.get(indexFile));
            if (tracked.isEmpty()) {
                System.out.println("No files added.");
                return;
            }
            System.out.println("Tracked files:");
            for (String filename : tracked) {
                System.out.println("  " + filename);
            }
        } catch (IOException e) {
            System.err.println("status error: " + e);
        }
    }

    public void log() {
        try {
            File dir = new File(commitsDir);
            File[] files = dir.listFiles();
            if (files == null || files.length == 0) {
                System.out.println("No commits yet.");
                return;
            }
            Arrays.sort(files, (a, b) -> b.getName().compareTo(a.getName()));
            for (File f : files) {
                String id = f.getName();
                List<String> lines = Files.readAllLines(f.toPath());
                String msg = "";
                if (!lines.isEmpty())
                    msg = lines.get(lines.size() - 1);
                System.out.println(id + ": " + msg);
            }
        } catch (IOException e) {
            System.err.println("log error: " + e);
        }
    }

    public void checkout(String commitid) {
        try {
            Path commitPath = Paths.get(commitsDir + File.separator + commitid);
            if (!Files.exists(commitPath)) {
                System.out.println("commit not found");
                return;
            }
            List<String> lines = Files.readAllLines(commitPath);
            for (String line : lines) {
                if (line.trim().isEmpty()) break;
                String[] parts = line.split(" ");
                if (parts.length != 2) continue;
                String fname = parts[0];
                String sha = parts[1];
                Path objPath = Paths.get(objectsDir + File.separator + sha);
                if (!Files.exists(objPath)) {
                    System.out.println("checkout error: object " + sha + " not found!");
                    continue;
                }
                byte[] content = Files.readAllBytes(objPath);
                Files.write(Paths.get(fname), content);
                System.out.println("restored " + fname);
            }
            Files.write(Paths.get(headFile), Arrays.asList(commitid), StandardCharsets.UTF_8);
        } catch (IOException e) {
            System.err.println("checkout error: " + e);
        }
    }

    private String toSHA1(byte[] bytes) {
        try {
            MessageDigest md = MessageDigest.getInstance("SHA-1");
            byte[] digest = md.digest(bytes);
            StringBuilder sb = new StringBuilder();
            for (byte b : digest)
                sb.append(String.format("%02x", b));
            return sb.toString();
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
