JFLAGS = -g
JC = javac

.SUFFIXES: .java .class

.java.class:
	$(JC) $(JFLAGS) $*.java

CLASSES = \
        Minigit.java \
        MiniGitRepo.java \

default: classes
	@echo "Build finished."

classes: $(CLASSES:.java=.class)

clean:
	rm -f *.class

minigit: classes
	echo '#!/bin/sh' > minigit
	echo 'java Minigit "$$@"' >> minigit
	chmod +x minigit
```

